mapper.select:
select b.id, b.match_user_id, b.match_user_name, b.branch_cd, b.branch_name, b.base_date, SUM(b.wages) wages, SUM(b.commission) commission, SUM(b.other_cost) other_cost, SUM(b.social_security) social_security, SUM(b.provident_fund) provident_fund, SUM(b.evection_cost) evection_cost, SUM(b.total_cost) total_cost, b.remark, MAX(b.created_date) created_date, MAX(b.updated_date) updated_date from t_rpt_base_cost b
and b.base_date >= #{baseStartDate}
and b.base_date <= #{baseEndDate}
and b.branch_cd = #{branchCd}
and b.match_user_name like CONCAT('%',#{matchUserName},'%')
and b.branch_cd in
#{branchCdList[${index}]}
group by b.match_user_id order by b.base_date desc, b.match_user_id asc

select SUM(b.wages) wages, SUM(b.commission) commission, SUM(b.other_cost) other_cost, SUM(b.social_security) social_security, SUM(b.provident_fund) provident_fund, SUM(b.evection_cost) evection_cost, SUM(b.total_cost) total_cost from t_rpt_base_cost b
and b.base_date >= #{baseStartDate}
and b.base_date <= #{baseEndDate}
and b.branch_cd = #{branchCd}
and b.match_user_name like CONCAT('%',#{matchUserName},'%')
and b.branch_cd in
#{branchCdList[${index}]}

select b.id, b.match_user_id, b.match_user_name, b.branch_cd, b.branch_name, b.base_date, SUM(b.wages) wages, SUM(b.commission) commission, SUM(b.other_cost) other_cost, SUM(b.social_security) social_security, SUM(b.provident_fund) provident_fund, SUM(b.evection_cost) evection_cost, SUM(b.total_cost) total_cost, b.remark, b.created_date, b.updated_date from t_rpt_base_cost b
and b.base_date >= #{param1}
and b.base_date <= #{param2}
and b.match_user_id in
#{item}
group by b.match_user_id order by b.base_date desc, b.match_user_id asc

SELECT c.sell_match_user_id AS sellMatchUserId, c.contract_time, c.buy_total_amount, c.sell_total_amount, c.deal_number, c.transport_amount, c.warehouse_amount, c.steve_dorage_amount, c.id AS contractId, c.sell_match_amount, c.delivery_fee, c.insurance_rate, c.vat_amount, c.print_amount FROM t_ctr_contract_settlement c LEFT JOIN t_ctr_contract sell ON c.sell_contract_id = sell.id WHERE c.business_type = 'ZY-BB' AND c.enable_flg = TRUE AND sell.seal_flg = TRUE
AND date_format(c.contract_time, '%Y-%m') >= #{param1}
AND date_format(c.contract_time, '%Y-%m') <= #{param2}

select b.match_user_name, b.base_date, b.match_user_id, b.branch_cd, b.branch_name, b.wages, c.sell_total_amount, c.transport_amount, c.warehouse_amount, c.steve_dorage_amount, c.buy_total_amount, c.contract_time, c.deal_number, c.business_type, c.match_credit_flg, c.business_type_dcsx, c.buy_contract_no, c.sell_contract_no from t_rpt_base_cost b join t_ctr_contract_settlement c on b.match_user_id = c.sell_match_user_id and c.business_type = 'ZY-BB' and c.enable_flg = true
and date_format(c.contract_time, '%Y-%m') = #{baseDate}
and b.base_date = #{baseDate}
and b.branch_cd = #{branchCd}
and b.branch_cd in
#{item}
